parameters.jsCode:
const PB_URL = ($('Config').first().json.pbUrl || '').replace(/\/+$/, '');
const token = $('PB Auth').first().json.token;
const pbH = { Authorization: token };
const fedId = (($('Webhook').first().json.body) || {}).id;

let out = $('AI Agent').first().json.output;
let parsed;
if (out && typeof out === 'object') { parsed = out; }
else {
  let raw = String(out || '').trim().replace(/^```(json)?/i, '').replace(/```$/, '').trim();
  try { parsed = JSON.parse(raw); }
  catch (e) { const m = raw.match(/\{[\s\S]*\}/); parsed = m ? JSON.parse(m[0]) : { found:false, notes:'unparseable agent output', _raw: raw.slice(0,300) }; }
}

const dirs = Array.isArray(parsed.directories) ? parsed.directories : [];
const m0 = dirs[0] || {};
const validM = ['static','js','api_endpoint','pdf','none'];
const method = validM.includes(parsed.extraction_method) ? parsed.extraction_method
             : (validM.includes(m0.extraction_method) ? m0.extraction_method : '');
let primary = parsed.primary_directory_url || m0.url || '';
if (!/^https?:\/\//i.test(primary)) primary = '';
const now = new Date().toISOString();

const noteStr = (parsed.confidence ? '[' + parsed.confidence + '] ' : '') + (parsed.notes || '');
// Never blank good existing directory_urls/method/status on an empty or failed re-discovery —
// only (over)write the directory fields when discovery actually found directories.
const patchBody = dirs.length > 0
  ? { club_directory_url: primary, directory_urls: dirs, extraction_method: method, status: 'needs_review', notes: noteStr, last_scraped: now }
  : { notes: noteStr, last_scraped: now };
await this.helpers.httpRequest({
  method: 'PATCH', url: PB_URL + '/api/collections/federations/records/' + fedId, headers: pbH,
  body: patchBody, json: true,
});

return [{ json: { ok: !!parsed.found, federation: fedId, primary_directory_url: primary, extraction_method: method, directories: dirs, confidence: parsed.confidence, notes: parsed.notes } }];

